// Code generated by go-mapp. DO NOT EDIT.
func MapPersonTypeToDto(pt domain.PersonType) (dto.PersonType, error) {
	switch pt {
	case domain.Simple:
		return dto.Simple, nil
	case domain.Important:
		return dto.Important, nil
	case domain.FUN:
		return dto.Fun, nil
	default:
		return 0, fmt.Errorf("unknown source enum: %v", pt)
	}
}

func MapPersonTypeToDomain(pt dto.PersonType) (domain.PersonType, error) {
	switch pt {
	case dto.Simple:
		return domain.Simple, nil
	case dto.Important:
		return domain.Important, nil
	case dto.Fun:
		return domain.FUN, nil
	default:
		return 0, fmt.Errorf("(\"I", pt)
	}
}

func MapPersonToDTO(src domain.Person) dto.Person {
	var mappedFirstName string
	if src.Firstname != nil {
		mappedFirstName = *src.Firstname
	}
	var mappedAccount []external.Account
	for _, a := range src.Account {
		var AccountStruct external.Account
		if a != nil {
			var AccountStructMappingErr error
			AccountStruct, AccountStructMappingErr = qytln(*a)
			if AccountStructMappingErr != nil {
				panic(fmt.Sprintf("error map from 'Account' to 'Account':%v", AccountStructMappingErr))
			}
		}
		mappedAccount = append(mappedAccount, AccountStruct)
	}
	var mappedProfile [][]dto.Profile
	if src.Profile != nil {
		for _, a := range *src.Profile {
			var ProfileSlice []dto.Profile
			for _, b := range a {
				var ProfileStruct dto.Profile
				var ProfileStructMappingErr error
				ProfileStruct, ProfileStructMappingErr = gvqcb(b)
				if ProfileStructMappingErr != nil {
					panic(fmt.Sprintf("error map from 'Profile' to 'Profile':%v", ProfileStructMappingErr))
				}
				ProfileSlice = append(ProfileSlice, ProfileStruct)
			}
			mappedProfile = append(mappedProfile, ProfileSlice)
		}
	}
	var mappedType dto.PersonType
	var mappedTypeMappingErr error
	mappedType, mappedTypeMappingErr = MapPersonTypeToDto(src.Type)
	if mappedTypeMappingErr != nil {
		panic("Panic")
	}

	return dto.Person{
		FirstName:   mappedFirstName,
		LastName:    src.LastName,
		MiddleName:  &src.MiddleName,
		Age:         src.Age,
		MainAccount: src.MainAccount,
		Account:     mappedAccount,
		Profile:     mappedProfile,
		Type:        mappedType,
		Projects:    src.Projects,
		// Email: ignored
	}
}
func qytln(src external.Account) (external.Account, error) {
	var err error

	return external.Account{
		Login:    src.Login,
		Password: src.Password,
	}, err
}
func gvqcb(src domain.Profile) (dto.Profile, error) {
	var err error

	return dto.Profile{
		Phone: src.Number,
	}, err
}
func MapPersonToDomain(src dto.Person) (domain.Person, error) {
	var err error
	var mappedMiddleName string
	if src.MiddleName != nil {
		mappedMiddleName = *src.MiddleName
	}
	var mappedAccount []*external.Account
	for _, a := range src.Account {
		var AccountPointer *external.Account
		var AccountPointerTmp external.Account
		AccountPointerTmp, err = qytln(a)
		if err != nil {
			return domain.Person{}, fmt.Errorf("error map from 'Account' to 'Account':%w", err)
		}
		AccountPointer = &AccountPointerTmp
		mappedAccount = append(mappedAccount, AccountPointer)
	}
	var mappedProfile [][]domain.Profile
	for _, a := range src.Profile {
		var ProfileSlice []domain.Profile
		for _, b := range a {
			var ProfileStruct domain.Profile
			ProfileStruct, err = ypkki(b)
			if err != nil {
				return domain.Person{}, fmt.Errorf("error map from 'Profile' to 'Profile':%w", err)
			}
			ProfileSlice = append(ProfileSlice, ProfileStruct)
		}
		mappedProfile = append(mappedProfile, ProfileSlice)
	}
	var mappedType domain.PersonType
	mappedType, err = MapPersonTypeToDomain(src.Type)
	if err != nil {
		panic("Panic")
	}

	return domain.Person{
		Firstname:  &src.FirstName,
		LastName:   src.LastName,
		MiddleName: mappedMiddleName,
		Age:        src.Age,
		// MainAccount: ignored
		Account:  mappedAccount,
		Profile:  &mappedProfile,
		Type:     mappedType,
		Projects: src.Projects,
	}, err
}
func ypkki(src dto.Profile) (domain.Profile, error) {
	var err error

	return domain.Profile{
		Number: src.Phone,
	}, err
}
